import logging
from logging.handlers import RotatingFileHandler
import json
import os

# Set up logging configuration
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s [%(levelname)s] %(message)s',
    datefmt='%Y-%m-%d %H:%M:%S'
)

class WebLogger(logging.Logger):
    def __init__(self, name):
        super().__init__(name)
        self.formatter = logging.Formatter('%(asctime)s [%(levelname)s] %(message)s')
        
        # Create a rotating file handler
        self.handler = RotatingFileHandler('web.log', maxBytes=10*1024*1024, backupCount=5)
        self.handler.setFormatter(self.formatter)
        
        # Add the handler to the logger
        self.addHandler(self.handler)

    def log_http_request(self, request):
        try:
            data = json.loads(request.body.decode('utf-8'))
            message = f"HTTP Request: {request.method} {request.path}\nData: {data}"
            self.info(message)
        except Exception as e:
            self.error(f"Error logging HTTP request: {e}")

def log_http_request(request):
    logger = WebLogger(__name__)
    logger.log_http_request(request)

# Example usage
if __name__ == "__main__":
    from flask import Flask, request
    
    app = Flask(__name__)
    
    @app.route('/log', methods=['POST'])
    def log():
        log_http_request(request)
